const debug = logger('quill:toolbar');

type Handler = (this: Toolbar, value: any) => void;

const sharedToolbars = new WeakMap<HTMLElement, SharedToolbar>();

class SharedToolbar {
  toolbars = new Set<Toolbar>();
  active?: Toolbar;
  observer: MutationObserver;

  constructor(readonly container: HTMLElement) {
    container.addEventListener('click', this.handleClick);
    container.addEventListener('change', this.handleChange);
    this.observer = new MutationObserver(() => this.updateControls());
    this.observer.observe(container, { childList: true, subtree: true });
  }

  add(toolbar: Toolbar) {
    this.toolbars.add(toolbar);
    if (this.active == null && this.toolbars.size === 1) {
      this.active = toolbar;
    }
    this.updateControls();
  }

  activate(toolbar: Toolbar) {
    this.prune();
    if (!this.toolbars.has(toolbar)) return;
    this.active = toolbar;
    this.updateControls();
  }

  prune() {
    this.toolbars.forEach((toolbar) => {
      if (!document.body.contains(toolbar.quill.root)) {
        this.toolbars.delete(toolbar);
        toolbar.destroy();
      }
    });
    if (this.active != null && !this.toolbars.has(this.active)) {
      this.active = undefined;
    }
  }

  getActive() {
    this.prune();
    return this.active;
  }

  private handleClick = (event: Event) => {
    const input = (event.target as HTMLElement).closest('button');
    if (input != null && this.container.contains(input)) {
      this.getActive()?.handle(input, event);
    }
  };

  private handleChange = (event: Event) => {
    const input = event.target as HTMLElement;
    if (input.tagName === 'SELECT' && this.container.contains(input)) {
      this.getActive()?.handle(input, event);
    }
  };

  updateControls() {
    const toolbar = this.getActive();
    const controls =
      this.container.querySelectorAll<HTMLElement>('button, select');
    if (toolbar == null) {
      controls.forEach((control) => {
        (control as HTMLButtonElement | HTMLSelectElement).disabled = true;
        control.classList.remove('ql-active');
        control.setAttribute('aria-pressed', 'false');
        updatePicker(control);
      });
      return;
    }
    toolbar.update(toolbar.quill.selection.getRange()[0]);
  }

  destroy() {
    this.observer.disconnect();
    this.container.removeEventListener('click', this.handleClick);
    this.container.removeEventListener('change', this.handleChange);
    sharedToolbars.delete(this.container);
  }
}

function updatePicker(input: HTMLElement) {
  // Picker instances are intentionally shared with the toolbar DOM.
  (
    input as HTMLElement & { __qlPicker?: { update: () => void } }
  ).__qlPicker?.update();
